341	/**
342	 * Helper function to create multiple InferenceSession objects.
343	 * 
344	 * @param {string} pretrained_model_name_or_path The path to the directory containing the model file.
345	 * @param {Record<string, string>} names The names of the model files to load.
346	 * @param {import('./utils/hub.js').PretrainedModelOptions} options Additional options for loading the model.
347	 * @returns {Promise<Record<string, any>>} A Promise that resolves to a dictionary of InferenceSession objects.
348	 * @private
349	 */
350	async function constructSessions(pretrained_model_name_or_path, names, options) {
351	    return Object.fromEntries(await Promise.all(
352	        Object.keys(names).map(async (name) => {
353	            const { buffer_or_path, session_options, session_config } = await getSession(pretrained_model_name_or_path, names[name], options);
354	            const session = await createInferenceSession(buffer_or_path, session_options, session_config);
355	            return [name, session];
356	        })
357	    ));
358	}
359	
360	/**
361	 * Helper function to load multiple optional configuration files
362	 * @param {string} pretrained_model_name_or_path The path to the directory containing the config file.
363	 * @param {Record<string, string>} names The names of the config files to load.
364	 * @param {import('./utils/hub.js').PretrainedModelOptions} options Additional options for loading the configs.
365	 * @returns {Promise<Record<string, any>>} A Promise that resolves to a dictionary of configuration objects.
366	 * @private
367	 */
368	async function getOptionalConfigs(pretrained_model_name_or_path, names, options) {
369	    return Object.fromEntries(await Promise.all(
370	        Object.keys(names).map(async (name) => {
371	            const config = await getModelJSON(pretrained_model_name_or_path, names[name], false, options);
372	            return [name, config];
373	        })
374	    ));
375	}
376	
377	/**
378	 * Validate model inputs
379	 * @param {Object} session The InferenceSession object that will be run.
380	 * @param {Object} inputs The inputs to check.
381	 * @returns {Record<string, Tensor>} The checked inputs.
382	 * @throws {Error} If any inputs are missing.
383	 * @private
384	 */
385	function validateInputs(session, inputs) {
386	    /**
387	     * NOTE: Create either a shallow or deep copy based on `onnx.wasm.proxy`
388	     * @type {Record<string, Tensor>}
389	     */
390	    const checkedInputs = Object.create(null);
391	    const missingInputs = [];
392	    for (const inputName of session.inputNames) {
393	        const tensor = inputs[inputName];
394	        // Rare case where one of the model's input names corresponds to a built-in
395	        // object name (e.g., toString), which would cause a simple (!tensor) check to fail,
396	        // because it's not undefined but a function.
397	        if (!(tensor instanceof Tensor)) {
398	            missingInputs.push(inputName);
