```javascript
/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Generate text based on an image and a text prompt.
 * @param {ImagePipelineInputs} images The image(s) to use as context.
 * @param {string|string[]} [text] The text prompt(s) to complete. If not provided, the model will generate text from the image(s) alone.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-Text-to-Text pipeline using a `AutoModelForImageTextToText`. This pipeline generates
 * text given an image and an optional text prompt.
 *
 * **Example:** Generate text from an image and text prompt with `Xenova/llava-v1.5-7b`.
 * ```javascript
 * const generator = await pipeline('image-text-to-text', 'Xenova/llava-v1.5-7b');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await generator(url, 'USER: <image>\nDescribe this image. ASSISTANT:');
 * // [{ generated_text: '...' }]
 * ```
 *
 * **Example:** Generate text with generation options.
 * ```javascript
 * const generator = await pipeline('image-text-to-text', 'Xenova/llava-v1.5-7b');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await generator(url, 'USER: <image>\nDescribe this image. ASSISTANT:', {
 *   max_new_tokens: 50,
 * });
 * // [{ generated_text: '...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text = null, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Run processor to get combined inputs
        const inputs = await this.processor(preparedImages.length === 1 ? preparedImages[0] : preparedImages, text);

        // Generate output tokens
        const output = await this.model.generate({ ...inputs, ...generate_kwargs });

        // Decode tokens
        const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
            skip_special_tokens: true,
        });

        /** @type {ImageTextToTextOutput[]} */
        const toReturn = decoded.map(x => [{ generated_text: x.trim() }]);

        return isBatched ? toReturn : toReturn[0];
    }
}
```

**Design notes on the `_call` implementation**:

1. **Image preparation**: Uses `prepareImages()` (lines 91-98 of pipelines.js), the standard utility that converts URLs/blobs/etc. to `RawImage` objects.

2. **Single vs. batched images**: When a single image is provided (not an array), we pass a single `RawImage` to the processor (not an array of length 1), matching the LLaVA test pattern: `processor(image, prompts[0])`. When batched, we pass the array.

3. **Processor call**: `this.processor(images, text)` -- passes both images and text to the processor. The processor handles combining them into `{pixel_values, input_ids, attention_mask}`. This works correctly for LLaVA-family processors.

4. **model.generate()**: Spreads the processor outputs plus any generation kwargs (like `max_new_tokens`, `temperature`, etc.) into the generate call. This matches the existing pattern in `TextGenerationPipeline` (line 1044) and the LLaVA test (line 43).

5. **Decoding**: Uses `this.tokenizer.batch_decode()` with `skip_special_tokens: true`, the standard pattern from `ImageToTextPipeline`.

6. **Output format**: Returns `[{ generated_text: "..." }]` for single images, `[[{ generated_text: "..." }], [...]]` for batched -- consistent with `ImageToTextPipeline`.

